// src/components/SummaryCards.js
import React from "react";

const CATEGORY_COLORS = {
  Food: "bg-orange-100 text-orange-700",
  Travel: "bg-blue-100 text-blue-700",
  Shopping: "bg-pink-100 text-pink-700",
  Education: "bg-purple-100 text-purple-700",
  Health: "bg-green-100 text-green-700",
  Entertainment: "bg-yellow-100 text-yellow-700",
  Other: "bg-gray-100 text-gray-700",
};

export default function SummaryCards({ total, summary, expenses }) {
  const thisMonth = expenses.filter((e) => {
    const d = new Date(e.date);
    const now = new Date();
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  });

  const monthTotal = thisMonth.reduce((s, e) => s + e.amount, 0);
  const topCategory = Object.entries(summary).sort((a, b) => b[1] - a[1])[0];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
      {/* Total kharcha */}
      <div className="bg-white rounded-xl border border-gray-200 p-5">
        <p className="text-sm text-gray-500 mb-1">Total Kharcha</p>
        <p className="text-2xl font-bold text-gray-800">₹{total.toLocaleString("en-IN")}</p>
        <p className="text-xs text-gray-400 mt-1">{expenses.length} transactions</p>
      </div>

      {/* Is mahine */}
      <div className="bg-white rounded-xl border border-gray-200 p-5">
        <p className="text-sm text-gray-500 mb-1">Is Mahine</p>
        <p className="text-2xl font-bold text-indigo-600">₹{monthTotal.toLocaleString("en-IN")}</p>
        <p className="text-xs text-gray-400 mt-1">{thisMonth.length} transactions</p>
      </div>

      {/* Sabse zyada kharcha category */}
      <div className="bg-white rounded-xl border border-gray-200 p-5">
        <p className="text-sm text-gray-500 mb-1">Sabse Zyada Kharcha</p>
        {topCategory ? (
          <>
            <span className={`inline-block px-2 py-0.5 rounded-full text-sm font-medium ${CATEGORY_COLORS[topCategory[0]] || "bg-gray-100 text-gray-700"}`}>
              {topCategory[0]}
            </span>
            <p className="text-xl font-bold text-gray-800 mt-1">
              ₹{topCategory[1].toLocaleString("en-IN")}
            </p>
          </>
        ) : (
          <p className="text-gray-400 text-sm mt-2">Abhi koi expense nahi</p>
        )}
      </div>
    </div>
  );
}
